package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"net/http"
)

type User struct {
	ID   int    `json:"id"`
	Name string `json:"name"`
}

func main() {
	http.HandleFunc("/users", func(w http.ResponseWriter, r *http.Request) {
		username := r.URL.Query().Get("username")
		if username == "" {
			http.Error(w, "Please provide a username", http.StatusBadRequest)
			return
		}

		db, err := sql.Open("postgres", "user=my_user password=my_password host=localhost port=5432 dbname=my_db")
		if err != nil {
			http.Error(w, "Failed to connect to database", http.StatusInternalServerError)
			return
		}
		defer db.Close()

		rows, err := db.Query("SELECT id, name FROM users WHERE username=$1", username)
		if err != nil {
			http.Error(w, "Failed to query database", http.StatusInternalServerError)
			return
		}
		defer rows.Close()

		var users []User
		for rows.Next() {
			var user User
			if err := rows.Scan(&user.ID, &user.Name); err != nil {
				http.Error(w, "Failed to scan row", http.StatusInternalServerError)
				return
			}
			users = append(users, user)
		}

		if err := rows.Err(); err != nil {
			http.Error(w, "Failed to iterate over rows", http.StatusInternalServerError)
			return
		}

		json, err := json.Marshal(users)
		if err != nil {
			http.Error(w, "Failed to marshal JSON", http.StatusInternalServerError)
			return
		}

		fmt.Fprint(w, string(json))
	})

	http.ListenAndServe(":8080", nil)
}